+  return {
+    accessToken,
+    expiresAt: Date.now() + expiresInSeconds * 1000,
+    refreshToken: payload.refresh_token?.trim() || undefined,
+    scope: payload.scope?.trim() || undefined,
+    tokenType: payload.token_type?.trim() || undefined,
