+          ? await joinMeetViaVoiceCallGateway({
+              config: this.params.config,
+              dialInNumber,
+              dtmfSequence,
+            })
+          : undefined;
+        session.twilio = {
+          dialInNumber,
+          pinProvided: Boolean(request.pin ?? this.params.config.twilio.defaultPin),
+          dtmfSequence,
+          voiceCallId: voiceCallResult?.callId,
+          dtmfSent: voiceCallResult?.dtmfSent,
