+    }
+    const stop = this.#sessionStops.get(sessionId);
+    if (stop) {
+      this.#sessionStops.delete(sessionId);
+      await stop();
+    }
+    session.state = "ended";
+    session.updatedAt = nowIso();
+    return { found: true, session };
+  }
+}

